import { AreaChart, Area, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer } from 'recharts';
import { useState, useEffect } from 'react';
import styles from './Dashboard.module.css';

interface CashFlowChartProps {
  oculto?: boolean;
}

export function CashFlowChart({ oculto = false }: CashFlowChartProps) {
  const [data, setData] = useState<any[]>([]);

  useEffect(() => {
    const savedT = localStorage.getItem('lca_financeiro');
    if (savedT) {
      const transacoes = JSON.parse(savedT);

      // Group by date
      const grouped = transacoes.reduce((acc: any, t: any) => {
        const date = t.data;
        if (!acc[date]) acc[date] = { date, receita: 0, distribuicao: 0 };
        if (t.tipo === 'receita') acc[date].receita += t.valor;
        else acc[date].distribuicao += t.valor;
        return acc;
      }, {});

      const chartData = Object.values(grouped)
        .sort((a: any, b: any) => new Date(a.date).getTime() - new Date(b.date).getTime())
        .map((item: any) => ({
          name: new Date(item.date).toLocaleDateString('pt-BR', { day: '2-digit', month: '2-digit' }),
          receita: item.receita,
          distribuicao: item.distribuicao
        }));

      setData(chartData);
    }
  }, []);

  return (
    <div className={`glass-panel ${styles.chartPanel}`}>
      <div className={styles.chartHeader}>
        <h3 className="text-serif">Fluxo de Caixa (Simulado)</h3>
        <p className="text-muted">Acompanhamento de receitas vs honor├írios pagos</p>
      </div>
      <div 
        className={styles.chartContainer}
        style={{ 
          filter: oculto ? 'blur(12px)' : 'none',
          userSelect: oculto ? 'none' : 'auto',
          transition: 'filter 0.3s ease',
          height: 300
        }}
      >
        {data.length > 0 ? (
          <ResponsiveContainer width="100%" height="100%">
            <AreaChart data={data} margin={{ top: 10, right: 10, left: 0, bottom: 0 }}>
              <defs>
                <linearGradient id="colorRec" x1="0" y1="0" x2="0" y2="1">
                  <stop offset="5%" stopColor="var(--color-primary)" stopOpacity={0.1}/>
                  <stop offset="95%" stopColor="var(--color-primary)" stopOpacity={0}/>
                </linearGradient>
                <linearGradient id="colorDist" x1="0" y1="0" x2="0" y2="1">
                  <stop offset="5%" stopColor="var(--color-accent)" stopOpacity={0.1}/>
                  <stop offset="95%" stopColor="var(--color-accent)" stopOpacity={0}/>
                </linearGradient>
              </defs>
              <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="var(--color-border)" />
              <XAxis dataKey="name" axisLine={false} tickLine={false} tick={{ fill: 'var(--color-text-muted)', fontSize: 12 }} />
              <YAxis axisLine={false} tickLine={false} tick={{ fill: 'var(--color-text-muted)', fontSize: 12 }} tickFormatter={(v) => `R$ ${v}`} />
              <Tooltip 
                contentStyle={{ background: 'var(--color-bg)', border: '1px solid var(--glass-border)', borderRadius: '12px' }}
                formatter={(v) => `R$ ${Number(v).toLocaleString('pt-BR')}`}
              />
              <Area type="monotone" dataKey="receita" stroke="var(--color-primary)" fillOpacity={1} fill="url(#colorRec)" strokeWidth={3} />
              <Area type="monotone" dataKey="distribuicao" stroke="var(--color-accent)" fillOpacity={1} fill="url(#colorDist)" strokeWidth={3} />
            </AreaChart>
          </ResponsiveContainer>
        ) : (
          <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'center', height: '100%' }}>
            <p className="text-muted">Cadastre receitas no Financeiro para visualizar o gr├ífico.</p>
          </div>
        )}
      </div>
    </div>
  );
}

import { useState, useEffect } from 'react';
import { 
  Plus, ChevronRight,
  Landmark, CreditCard, Building2, Coins, ChevronLeft,
  Edit2, Trash2, ArrowUpRight, ArrowDownRight, Scale,
  PieChart as PieChartIcon, Calculator
} from 'lucide-react';
import { motion, AnimatePresence } from 'framer-motion';
import { toast } from 'sonner';

const TRANSACOES_KEY = 'lca_financeiro';
const BALANCE_KEY = 'lca_saldo_inicial';
const CLIENTS_KEY = 'lca_clientes';
const COLABS_KEY = 'lca_colaboradores';
const PROCESSOS_KEY = 'lca_processos';

interface ColabShare { id: number; nome: string; percentual: number; }

interface Processo {
  id: string;
  numero: string;
  clienteId: number;
  clienteNome: string;
  valorTotal: number;
  imposto: number;
  parcelas: number;
  colaboradores: ColabShare[];
  dataInicio: string;
  status: 'ativo' | 'concluido' | 'suspenso';
}

interface Transacao {
  id: string;
  tipo: 'receita' | 'despesa' | 'distribuicao';
  valor: number;
  data: string;
  entidade: string;
  status: 'pendente' | 'recebido' | 'pago';
  concretizado: boolean; // New field
  referencia: string;
  conta: string;
}

const CONTAS = [
  { id: 'BB', nome: 'Banco do Brasil', icone: <Landmark size={16} /> },
  { id: 'Asaas', nome: 'Asaas', icone: <CreditCard size={16} /> },
  { id: 'Nubank', nome: 'Nubank', icone: <CreditCard size={16} /> },
  { id: 'Sicoob', nome: 'Sicoob', icone: <Building2 size={16} /> },
  { id: 'Dinheiro', nome: 'Dinheiro', icone: <Coins size={16} /> },
];

const MESES = [
  'Janeiro', 'Fevereiro', 'Mar├ºo', 'Abril', 'Maio', 'Junho',
  'Julho', 'Agosto', 'Setembro', 'Outubro', 'Novembro', 'Dezembro'
];

export function Financeiro() {
  const [activeTab, setActiveTab] = useState<'resumo' | 'receitas' | 'despesas' | 'processos' | 'simulador'>('resumo');
  const [transacoes, setTransacoes] = useState<Transacao[]>([]);
  const [processos, setProcessos] = useState<Processo[]>([]);
  const [saldoInfo, setSaldoInfo] = useState<Record<string, number>>({ BB: 0, Asaas: 0, Nubank: 0, Sicoob: 0, Dinheiro: 0 });
  const [clientes, setClientes] = useState<any[]>([]);
  const [colaboradores, setColaboradores] = useState<any[]>([]);

  const now = new Date();
  const [mesSelecionado, setMesSelecionado] = useState(now.getMonth());
  const [anoSelecionado] = useState(now.getFullYear());

  const [modalProcesso, setModalProcesso] = useState(false);
  const [editandoProcesso, setEditandoProcesso] = useState<Processo | null>(null);
  const [modalTransacao, setModalTransacao] = useState(false);
  const [tipoTransacao, setTipoTransacao] = useState<'receita' | 'despesa'>('receita');

  const [formProcesso, setFormProcesso] = useState({
    numero: '', clienteId: '', valorTotal: '', imposto: '5', parcelas: '1', colaboradores: [] as ColabShare[], dataInicio: now.toISOString().split('T')[0]
  });

  const [formTrans, setFormTrans] = useState({
    entidade: '', valor: '', data: now.toISOString().split('T')[0], status: 'pendente' as any, concretizado: false, referencia: '', conta: 'BB'
  });

  useEffect(() => {
    const savedT = localStorage.getItem(TRANSACOES_KEY);
    if (savedT) setTransacoes(JSON.parse(savedT));
    const savedP = localStorage.getItem(PROCESSOS_KEY);
    if (savedP) setProcessos(JSON.parse(savedP));
    const savedS = localStorage.getItem(BALANCE_KEY);
    if (savedS) setSaldoInfo(JSON.parse(savedS));
    const savedC = localStorage.getItem(CLIENTS_KEY);
    if (savedC) setClientes(JSON.parse(savedC));
    const savedCo = localStorage.getItem(COLABS_KEY);
    if (savedCo) setColaboradores(JSON.parse(savedCo));
  }, []);

  const salvarT = (items: Transacao[]) => { 
    setTransacoes(items); 
    localStorage.setItem(TRANSACOES_KEY, JSON.stringify(items)); 
  };

  const handleSalvarProcesso = () => {
    if (!formProcesso.numero || !formProcesso.clienteId || !formProcesso.valorTotal) {
      toast.error('Campos obrigat├│rios faltando');
      return;
    }
    const cliente = clientes.find(c => c.id === Number(formProcesso.clienteId));
    const novo: Processo = {
      id: editandoProcesso ? editandoProcesso.id : Math.random().toString(36).substr(2, 9),
      numero: formProcesso.numero, clienteId: Number(formProcesso.clienteId), clienteNome: cliente?.nome || 'N/A',
      valorTotal: parseFloat(formProcesso.valorTotal), imposto: parseFloat(formProcesso.imposto),
      parcelas: parseInt(formProcesso.parcelas), colaboradores: formProcesso.colaboradores,
      dataInicio: formProcesso.dataInicio, status: 'ativo'
    };
    const updated = editandoProcesso ? processos.map(p => p.id === editandoProcesso.id ? novo : p) : [...processos, novo];
    setProcessos(updated);
    localStorage.setItem(PROCESSOS_KEY, JSON.stringify(updated));
    setModalProcesso(false); setEditandoProcesso(null);
    toast.success('Processo registrado');
  };

  const handleSalvarTransacao = () => {
    if (!formTrans.entidade || !formTrans.valor) return toast.error('Preencha os dados');
    const item: Transacao = {
      id: Math.random().toString(36).substr(2, 9),
      tipo: tipoTransacao, valor: parseFloat(formTrans.valor), data: formTrans.data,
      entidade: formTrans.entidade, status: formTrans.status, 
      concretizado: formTrans.status === 'recebido' || formTrans.status === 'pago',
      referencia: formTrans.referencia, conta: formTrans.conta
    };

    // Auto-distribution logic if linked to a process
    const extraTasks: Transacao[] = [];
    const proc = processos.find(p => p.numero === formTrans.referencia);
    if (tipoTransacao === 'receita' && proc) {
        // Calculate tax
        const vImposto = item.valor * (proc.imposto / 100);
        if (vImposto > 0) {
            extraTasks.push({
                id: Math.random().toString(36).substr(2, 9),
                tipo: 'despesa', valor: vImposto, data: formTrans.data,
                entidade: 'Governo (Impostos)', status: 'pendente', concretizado: false, referencia: `Imposto ${proc.numero}`, conta: formTrans.conta
            });
        }
        // Calculate colab shares
        proc.colaboradores.forEach(c => {
            extraTasks.push({
                id: Math.random().toString(36).substr(2, 9),
                tipo: 'distribuicao', valor: item.valor * (c.percentual / 100), data: formTrans.data,
                entidade: c.nome, status: 'pendente', concretizado: false, referencia: proc.numero, conta: formTrans.conta
            });
        });
    }

    salvarT([item, ...extraTasks, ...transacoes]);
    setModalTransacao(false);
    toast.success('Lan├ºamento realizado');
  };

  const formatarDataBR = (data: string) => {
    const [y, m, d] = data.split('-');
    return `${d}/${m}/${y}`;
  };

  const getSaldoConta = (contaId: string) => {
    const inicial = saldoInfo[contaId] || 0;
    const refDate = new Date(anoSelecionado, mesSelecionado + 1, 0);
    const receitas = transacoes.filter(t => t.tipo === 'receita' && t.concretizado && t.conta === contaId && new Date(t.data) <= refDate).reduce((s,t) => s+t.valor, 0);
    const saidas = transacoes.filter(t => (t.tipo === 'despesa' || t.tipo === 'distribuicao') && t.concretizado && t.conta === contaId && new Date(t.data) <= refDate).reduce((s,t) => s+t.valor, 0);
    return inicial + receitas - saidas;
  };

  const handleConfirmarPagamento = (id: string) => {
    const updated = transacoes.map(t => t.id === id ? { ...t, concretizado: true, status: t.tipo === 'receita' ? 'recebido' : 'pago' as any } : t);
    salvarT(updated);
    toast.success('Transa├º├úo confirmada (Realizado)');
  };

  const handleImprimirRelatorio = () => {
    const rTot = transFiltered.filter(t => t.tipo === 'receita').reduce((s,t) => s+t.valor, 0);
    const rReal = transFiltered.filter(t => t.tipo === 'receita' && t.concretizado).reduce((s,t) => s+t.valor, 0);
    const dTot = transFiltered.filter(t => t.tipo !== 'receita').reduce((s,t) => s+t.valor, 0);
    const dReal = transFiltered.filter(t => t.tipo !== 'receita' && t.concretizado).reduce((s,t) => s+t.valor, 0);

    const doc = `
      <html>
        <head>
          <title>Relat├│rio Financeiro - ${MESES[mesSelecionado]}/${anoSelecionado}</title>
          <style>
            body { font-family: sans-serif; padding: 30px; }
            h1, h2 { text-align: center; color: #1a1a1a; }
            .header-info { margin-bottom: 30px; border-bottom: 2px solid #eee; padding-bottom: 15px; }
            table { width: 100%; border-collapse: collapse; margin-top: 20px; }
            th, td { border: 1px solid #ddd; padding: 10px; text-align: left; font-size: 13px; }
            th { background: #f8f9fa; }
            .summary { display: grid; grid-template-columns: 1fr 1fr; gap: 20px; margin-top: 30px; }
            .summary-card { border: 1px solid #ddd; padding: 15px; border-radius: 8px; }
            @media print { .no-print { display: none; } }
          </style>
        </head>
        <body>
          <h1>Relat├│rio Interno - LCA DADOS</h1>
          <div class="header-info">
             <p><strong>M├¬s de Refer├¬ncia:</strong> ${MESES[mesSelecionado]} ${anoSelecionado}</p>
             <p><strong>Data de Emiss├úo:</strong> ${new Date().toLocaleDateString('pt-BR')}</p>
          </div>

          <div class="summary">
             <div class="summary-card">
                <h3>RECEITAS</h3>
                <p>Previs├úo: R$ ${rTot.toLocaleString('pt-BR')}</p>
                <p>Realizado: R$ ${rReal.toLocaleString('pt-BR')}</p>
             </div>
             <div class="summary-card">
                <h3>DESPESAS / DISTRIBUICAO</h3>
                <p>Previs├úo: R$ ${dTot.toLocaleString('pt-BR')}</p>
                <p>Realizado: R$ ${dReal.toLocaleString('pt-BR')}</p>
             </div>
          </div>

          <h2>Detalhamento das Opera├º├Áes</h2>
          <table>
            <thead>
              <tr>
                <th>Data</th>
                <th>Descri├º├úo / Entidade</th>
                <th>Refer├¬ncia</th>
                <th>Status</th>
                <th>Valor</th>
              </tr>
            </thead>
            <tbody>
              ${transFiltered.map(t => `
                <tr>
                  <td>${formatarDataBR(t.data)}</td>
                  <td>${t.entidade}</td>
                  <td>${t.referencia || '-'}</td>
                  <td>${t.concretizado ? 'REALIZADO' : 'PREVISTO'}</td>
                  <td style="text-align: right">R$ ${t.valor.toLocaleString('pt-BR')}</td>
                </tr>
              `).join('')}
            </tbody>
          </table>

          <div class="no-print" style="position: fixed; top: 20px; right: 20px;">
             <button onclick="window.print()" style="padding: 10px 20px; background: #2563eb; color: #fff; border: none; border-radius: 6px; cursor: pointer;">Imprimir Relat├│rio</button>
          </div>
        </body>
      </html>
    `;
    const win = window.open('', '_blank');
    if (win) { win.document.write(doc); win.document.close(); } else { toast.error('Bloqueador de pop-ups ativo.'); }
  };

  const transFiltered = transacoes.filter(t => {
    const d = new Date(t.data);
    return d.getMonth() === mesSelecionado && d.getFullYear() === anoSelecionado;
  });

  return (
    <div className="animate-in">
      <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '2rem' }}>
        <div>
          <h1 className="text-serif" style={{ fontSize: '2.5rem' }}>Fluxo de Caixa</h1>
          <p className="text-muted">Gest├úo estrat├®gica e financeira.</p>
        </div>
        <div style={{ display: 'flex', gap: '0.75rem' }}>
            <button onClick={() => setMesSelecionado(m => m === 0 ? 11 : m - 1)} className="btn-outline" style={{ borderRadius: '50%', padding: '0.6rem' }}><ChevronLeft size={18} /></button>
            <div className="glass-panel flex-center" style={{ minWidth: '150px', fontWeight: 600 }}>{MESES[mesSelecionado]} {anoSelecionado}</div>
            <button onClick={() => setMesSelecionado(m => m === 11 ? 0 : m + 1)} className="btn-outline" style={{ borderRadius: '50%', padding: '0.6rem' }}><ChevronRight size={18} /></button>
        </div>
      </div>

      <div style={{ display: 'flex', gap: '0.5rem', marginBottom: '2rem', overflowX: 'auto', paddingBottom: '0.5rem' }}>
        {[
          {id: 'resumo', label: 'Resumo', icon: <PieChartIcon size={16}/>},
          {id: 'processos', label: 'Processos', icon: <Scale size={16}/>},
          {id: 'receitas', label: 'Receitas', icon: <ArrowUpRight size={16}/>},
          {id: 'despesas', label: 'Despesas', icon: <ArrowDownRight size={16}/>},
          {id: 'simulador', label: 'Simulador', icon: <Calculator size={16}/>}
        ].map(t => (
          <button key={t.id} onClick={() => setActiveTab(t.id as any)} className={activeTab === t.id ? 'btn-primary flex-center' : 'btn-outline flex-center'} style={{ gap: '0.5rem', borderRadius: '12px', whiteSpace: 'nowrap' }}>
            {t.icon} {t.label}
          </button>
        ))}
      </div>

      <AnimatePresence mode="wait">
        {activeTab === 'resumo' && (
          <motion.div key="resumo" initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }}>
             <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(300px, 1fr))', gap: '1.5rem' }}>
                <div className="glass-panel" style={{ padding: '1.5rem' }}>
                    <p className="text-muted">Liquidez Consolidada</p>
                    <h2 style={{ fontSize: '2.5rem', margin: '0.5rem 0', color: 'var(--color-primary)' }}>R$ {CONTAS.reduce((s,c) => s+getSaldoConta(c.id), 0).toLocaleString('pt-BR')}</h2>
                    <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '0.5rem', marginTop: '1rem' }}>
                        {CONTAS.map(c => (
                            <div key={c.id} style={{ display: 'flex', justifyContent: 'space-between', fontSize: '0.7rem', background: 'rgba(0,0,0,0.03)', padding: '0.5rem', borderRadius: '8px' }}>
                                <span className="flex-center" style={{ gap: '0.4rem' }}>{c.icone} {c.id}</span>
                                <strong>R$ {getSaldoConta(c.id).toLocaleString('pt-BR')}</strong>
                            </div>
                        ))}
                    </div>
                </div>
                <div className="glass-panel" style={{ padding: '1.5rem' }}>
                    <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '1rem' }}>
                        <p className="text-muted" style={{ margin: 0 }}>Movimenta├º├úo Mensal</p>
                        <button onClick={handleImprimirRelatorio} className="btn-outline" style={{ fontSize: '0.7rem' }}>Exibir Relat├│rio Interno</button>
                    </div>
                    <div style={{ marginTop: '0.5rem', display: 'flex', flexDirection: 'column', gap: '1rem' }}>
                        <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '1rem' }}>
                            <div style={{ background: 'rgba(0,0,0,0.02)', padding: '0.75rem', borderRadius: '10px' }}>
                                <span className="text-muted" style={{ fontSize: '0.65rem' }}>Entradas (Previsto)</span>
                                <h4 style={{ margin: 0 }}>R$ {transFiltered.filter(t => t.tipo === 'receita').reduce((s,t) => s+t.valor, 0).toLocaleString('pt-BR')}</h4>
                            </div>
                            <div style={{ background: 'var(--color-success-bg)', padding: '0.75rem', borderRadius: '10px', color: 'var(--color-success)' }}>
                                <span style={{ fontSize: '0.65rem', opacity: 0.8 }}>Entradas (Realizado)</span>
                                <h4 style={{ margin: 0 }}>R$ {transFiltered.filter(t => t.tipo === 'receita' && t.concretizado).reduce((s,t) => s+t.valor, 0).toLocaleString('pt-BR')}</h4>
                            </div>
                        </div>
                        <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '1rem' }}>
                            <div style={{ background: 'rgba(0,0,0,0.02)', padding: '0.75rem', borderRadius: '10px' }}>
                                <span className="text-muted" style={{ fontSize: '0.65rem' }}>Sa├¡das (Previsto)</span>
                                <h4 style={{ margin: 0 }}>R$ {transFiltered.filter(t => t.tipo !== 'receita').reduce((s,t) => s+t.valor, 0).toLocaleString('pt-BR')}</h4>
                            </div>
                            <div style={{ background: 'var(--color-warning-bg)', padding: '0.75rem', borderRadius: '10px', color: 'var(--color-warning)' }}>
                                <span style={{ fontSize: '0.65rem', opacity: 0.8 }}>Sa├¡das (Realizado)</span>
                                <h4 style={{ margin: 0 }}>R$ {transFiltered.filter(t => t.tipo !== 'receita' && t.concretizado).reduce((s,t) => s+t.valor, 0).toLocaleString('pt-BR')}</h4>
                            </div>
                        </div>
                        <div style={{ borderTop: '1px solid var(--color-border)', paddingTop: '1rem', display: 'flex', justifyContent: 'space-between', fontWeight: 700 }}>
                            <span>Saldo L├¡quido Realizado</span>
                            <span style={{ color: 'var(--color-primary)' }}>R$ {(transFiltered.filter(t => t.tipo === 'receita' && t.concretizado).reduce((s,t) => s+t.valor, 0) - transFiltered.filter(t => t.tipo !== 'receita' && t.concretizado).reduce((s,t) => s+t.valor, 0)).toLocaleString('pt-BR')}</span>
                        </div>
                    </div>
                </div>
             </div>
          </motion.div>
        )}

        {activeTab === 'processos' && (
          <motion.div key="processos" initial={{ opacity: 0 }} animate={{ opacity: 1 }}>
            <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '1rem' }}>
                <h3 className="text-serif">Contratos & Processos</h3>
                <button onClick={() => { setEditandoProcesso(null); setModalProcesso(true); }} className="btn-primary flex-center" style={{ gap: '0.5rem' }}><Plus size={18}/> Novo Processo</button>
            </div>
            <div className="glass-panel" style={{ padding: 0, overflow: 'hidden' }}>
                <table style={{ width: '100%', borderCollapse: 'collapse' }}>
                    <thead style={{ background: 'rgba(0,0,0,0.02)' }}>
                        <tr style={{ textAlign: 'left', borderBottom: '1px solid var(--color-border)' }}>
                            <th style={{ padding: '1rem' }}>N├║mero / In├¡cio</th>
                            <th style={{ padding: '1rem' }}>Cliente</th>
                            <th style={{ padding: '1rem' }}>Valor Total</th>
                            <th style={{ padding: '1rem' }}>Distribui├º├úo (%)</th>
                            <th style={{ padding: '1rem' }}>Status</th>
                            <th style={{ padding: '1rem' }}></th>
                        </tr>
                    </thead>
                    <tbody>
                        {processos.map(p => (
                            <tr key={p.id} style={{ borderBottom: '1px solid var(--color-border)' }}>
