                                    <span style={{ color: 'var(--color-primary)' }}>R$ {(parseFloat(formProcesso.valorTotal || '0') * (1 - (parseFloat(formProcesso.imposto)/100) - 0.3)).toLocaleString('pt-BR')}</span>
