                </motion.div>
            </div>
        )}
      </AnimatePresence>
    </div>
  );
}

import { useState, useEffect } from 'react';
import { motion } from 'framer-motion';
import { LogIn, DollarSign, Calendar, TrendingUp, History, User, LogOut, FileText } from 'lucide-react';
import { pageVariants, pageTransition } from '../lib/animations';
import { toast } from 'sonner';

interface Distribuicao {
  id: number;
  entidade: string;
  referencia: string;
  valor: number;
  data: string;
  status: 'pendente' | 'recebido' | 'pago';
  baseLiquida?: number;
  percentual?: number;
}

export function PortalColaborador() {
  const [session, setSession] = useState<{ id: number; nome: string; OAB: string } | null>(null);
  const [loginInput, setLoginInput] = useState('');
  const [distribuicoes, setDistribuicoes] = useState<Distribuicao[]>([]);
  const [colaboradores, setColaboradores] = useState<any[]>([]);

  // Load registered collaborators to simulate login
  useEffect(() => {
    const savedColabs = localStorage.getItem('lca_colaboradores');
    if (savedColabs) setColaboradores(JSON.parse(savedColabs));

    // Check if there's a portal session
    const savedSession = sessionStorage.getItem('lca_portal_session');
    if (savedSession) setSession(JSON.parse(savedSession));
  }, []);

  // Load financial data when logged in
  useEffect(() => {
    if (session) {
      const savedTrans = localStorage.getItem('lca_financeiro');
      if (savedTrans) {
        const allTrans = JSON.parse(savedTrans);
        // Filter distributions for this specific collaborator by name (exact match in this simulation)
        const myDists = allTrans.filter((t: any) => 
          t.tipo === 'distribuicao' && t.entidade === session.nome
        );
        setDistribuicoes(myDists);
      }
    }
  }, [session]);

  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    const user = colaboradores.find(c => 
      c.nome.toLowerCase() === loginInput.toLowerCase() || 
      c.OAB.toLowerCase() === loginInput.toLowerCase()
    );

    if (user) {
      const sessionData = { id: user.id, nome: user.nome, OAB: user.OAB };
      setSession(sessionData);
      sessionStorage.setItem('lca_portal_session', JSON.stringify(sessionData));
      toast.success(`Bem-vindo, ${user.nome}!`);
    } else {
      toast.error('Profissional n├úo encontrado. Verifique os dados ou contate a administra├º├úo.');
    }
  };

  const logout = () => {
    setSession(null);
    sessionStorage.removeItem('lca_portal_session');
    toast.info('Sess├úo encerrada.');
  };

  if (!session) {
    return (
      <div style={{ 
        minHeight: '100vh', display: 'flex', alignItems: 'center', justifyContent: 'center',
        background: 'linear-gradient(135deg, #171717 0%, #262626 100%)', padding: '1rem' 
      }}>
        <motion.div 
          initial={{ opacity: 0, scale: 0.95 }}
          animate={{ opacity: 1, scale: 1 }}
          className="glass-panel"
          style={{ width: '100%', maxWidth: '400px', padding: '2.5rem', textAlign: 'center', border: '1px solid rgba(255,255,255,0.1)' }}
        >
          <div style={{ 
            width: '64px', height: '64px', background: 'var(--color-primary)', 
            borderRadius: '16px', margin: '0 auto 1.5rem', display: 'flex', 
            alignItems: 'center', justifyContent: 'center', color: 'white' 
          }}>
            <LogIn size={32} />
          </div>
          <h2 className="text-serif" style={{ color: 'white', marginBottom: '0.5rem' }}>Portal do Colaborador</h2>
          <p style={{ color: 'rgba(255,255,255,0.6)', fontSize: '0.875rem', marginBottom: '2rem' }}>Acesse sua previs├úo de honor├írios e contracheque.</p>

          <form onSubmit={handleLogin} style={{ textAlign: 'left' }}>
            <div style={{ display: 'flex', flexDirection: 'column', gap: '0.5rem', marginBottom: '1.5rem' }}>
              <label style={{ color: 'rgba(255,255,255,0.8)', fontSize: '0.875rem' }}>Nome ou OAB</label>
              <input 
                type="text" 
                value={loginInput}
                onChange={(e) => setLoginInput(e.target.value)}
                placeholder="Identifique-se..." 
                style={{ 
                  background: 'rgba(255,255,255,0.05)', border: '1px solid rgba(255,255,255,0.1)', 
                  color: 'white', padding: '0.75rem', borderRadius: '8px' 
                }}
              />
            </div>
            <button className="btn-primary" style={{ width: '100%', padding: '0.75rem', fontWeight: 600 }}>Entrar no Portal</button>
          </form>
        </motion.div>
      </div>
    );
  }

  const pendentes = distribuicoes.filter(d => d.status === 'pendente');
  const pagas = distribuicoes.filter(d => d.status === 'pago' || d.status === 'recebido'); // In this sim, received = ready to pay
  const totalPrevisto = pendentes.reduce((sum, d) => sum + d.valor, 0);

  return (
    <motion.div
      initial="initial"
      animate="in"
      exit="out"
      variants={pageVariants}
      transition={pageTransition}
      style={{ minHeight: '100vh', background: '#f8fafc', padding: '2rem' }}
    >
      <div style={{ maxWidth: '1000px', margin: '0 auto' }}>
        <header style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '2.5rem' }}>
          <div>
            <div style={{ display: 'flex', alignItems: 'center', gap: '0.75rem', marginBottom: '0.25rem' }}>
              <User size={20} className="text-primary" />
              <h2 className="text-serif" style={{ margin: 0 }}>{session.nome}</h2>
            </div>
            <p className="text-muted" style={{ margin: 0 }}>OAB: {session.OAB} ÔÇó Portal de Honor├írios</p>
          </div>
          <button onClick={logout} className="btn-outline flex-center" style={{ gap: '0.5rem', border: 'none', color: 'var(--color-danger)' }}>
            <LogOut size={18} /> Sair
          </button>
        </header>

        <div style={{ display: 'grid', gridTemplateColumns: '1.5fr 1fr', gap: '1.5rem', marginBottom: '1.5rem' }}>
           <div className="glass-panel" style={{ padding: '2rem', background: 'var(--color-primary)', color: 'white' }}>
              <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start' }}>
                 <div>
                    <span style={{ fontSize: '0.875rem', opacity: 0.9 }}>Previs├úo de Honor├írios (Pendentes)</span>
                    <h1 style={{ margin: '0.5rem 0 0', fontSize: '3rem' }}>R$ {totalPrevisto.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}</h1>
                 </div>
                 <TrendingUp size={48} style={{ opacity: 0.2 }} />
              </div>
              <p style={{ marginTop: '2rem', fontSize: '0.875rem', opacity: 0.8 }}>Baseado nos processos ativos sob sua responsabilidade.</p>
           </div>

           <div className="glass-panel" style={{ padding: '1.5rem', display: 'flex', flexDirection: 'column', justifyContent: 'center' }}>
              <div style={{ display: 'flex', alignItems: 'center', gap: '1rem', marginBottom: '1rem' }}>
                 <div style={{ background: 'rgba(34, 197, 94, 0.1)', color: '#16a34a', padding: '0.75rem', borderRadius: '12px' }}>
                    <DollarSign size={24} />
                 </div>
                 <div>
                    <span className="text-muted" style={{ fontSize: '0.75rem' }}>J├í Recebido (M├¬s Atual)</span>
                    <h3 style={{ margin: 0 }}>R$ {pagas.reduce((sum, d) => sum + d.valor, 0).toLocaleString('pt-BR', { minimumFractionDigits: 2 })}</h3>
                 </div>
              </div>
              <div style={{ display: 'flex', alignItems: 'center', gap: '1rem' }}>
                 <div style={{ background: 'rgba(59, 130, 246, 0.1)', color: '#2563eb', padding: '0.75rem', borderRadius: '12px' }}>
                    <Calendar size={24} />
                 </div>
                 <div>
                    <span className="text-muted" style={{ fontSize: '0.75rem' }}>Pr├│xima Data Prevista</span>
                    <h3 style={{ margin: 0 }}>{pendentes.length > 0 ? pendentes[0].data : '--/--/----'}</h3>
                 </div>
              </div>
           </div>
        </div>

        <div style={{ display: 'grid', gridTemplateColumns: '1fr', gap: '1.5rem' }}>
            <div className={`glass-panel`} style={{ padding: '1.5rem' }}>
                <div style={{ display: 'flex', alignItems: 'center', gap: '0.5rem', marginBottom: '1.5rem' }}>
                    <History size={20} className="text-primary" />
                    <h3 className="text-serif" style={{ margin: 0 }}>Extrato de Distribui├º├Áes</h3>
                </div>

                <div style={{ display: 'flex', flexDirection: 'column', gap: '0.75rem' }}>
                    {distribuicoes.length > 0 ? distribuicoes.map(d => (
                        <div key={d.id} style={{ 
                            display: 'flex', justifyContent: 'space-between', alignItems: 'center', 
                            padding: '1rem', borderRadius: '12px', background: 'rgba(0,0,0,0.02)',
                            border: '1px solid var(--color-border)'
                        }}>
                            <div>
                                <div style={{ fontWeight: 600, fontSize: '0.925rem' }}>{d.referencia}</div>
                                <div className="text-muted" style={{ fontSize: '0.75rem' }}>Base: R$ {d.baseLiquida?.toLocaleString('pt-BR')} ÔÇó {d.percentual}% de comiss├úo</div>
                            </div>
                            <div style={{ textAlign: 'right' }}>
                                <div style={{ fontWeight: 700, color: d.status === 'pendente' ? 'var(--color-warning)' : 'var(--color-success)' }}>
                                    R$ {d.valor.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}
                                </div>
                                <span style={{ fontSize: '0.7rem', display: 'flex', alignItems: 'center', justifyContent: 'flex-end', gap: '0.25rem', color: 'var(--color-primary)' }}>
                                    {d.status === 'pendente' ? 'Previs├úo para ' + d.data : 'Pago em ' + d.data}
                                </span>
                            </div>
                        </div>
                    )) : (
                        <div style={{ textAlign: 'center', padding: '3rem', background: 'rgba(0,0,0,0.01)', borderRadius: '12px', border: '1px dashed var(--color-border)' }}>
                            <FileText size={40} className="text-muted" style={{ marginBottom: '1rem' }} />
                            <p className="text-muted">Nenhum lan├ºamento financeiro registrado para o seu perfil.</p>
                        </div>
                    )}
                </div>
            </div>

            <div className="glass-panel" style={{ padding: '1.5rem', borderLeft: '4px solid var(--color-primary)' }}>
                 <h4 className="text-serif" style={{ margin: '0 0 0.5rem' }}>Suporte Administrativo</h4>
                 <p className="text-muted" style={{ fontSize: '0.875rem', margin: 0 }}>Qualquer diverg├¬ncia nos valores, favor entrar em contato com o setor financeiro do escrit├│rio.</p>
            </div>
        </div>
      </div>
    </motion.div>
  );
}

import { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { Scale, Lock } from 'lucide-react';
import { motion } from 'framer-motion';
import { toast } from 'sonner';
import { supabase } from '../lib/supabase';

export function UpdatePassword() {
  const [password, setPassword] = useState('');
  const [confirmPassword, setConfirmPassword] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const navigate = useNavigate();

  useEffect(() => {
    // O Supabase lida com o token da URL automaticamente no cliente.
    // Se por algum motivo o usu├írio cair aqui sem sess├úo de recberia├º├úo, avisar:
    supabase.auth.getSession().then(({ data: { session } }) => {
      if (!session) {
        toast.error('Sess├úo inv├ílida', { description: 'O link de recupera├º├úo expirou ou ├® inv├ílido.'});
        navigate('/login');
      }
    });
  }, [navigate]);

  const handleUpdate = async (e: React.FormEvent) => {
    e.preventDefault();

    if (password.length < 6) {
      toast.error('A senha deve ter no m├¡nimo 6 caracteres.');
      return;
    }

    if (password !== confirmPassword) {
      toast.error('As senhas n├úo coincidem.');
      return;
    }

    setIsLoading(true);
    try {
      const { error } = await supabase.auth.updateUser({
        password: password
      });

      if (error) throw error;

      toast.success('Senha atualizada com sucesso!', {
        description: 'Voc├¬ j├í pode usar sua nova senha.'
      });
      navigate('/');
    } catch (error: any) {
      toast.error('Erro ao atualizar senha', {
        description: error.message || 'Ocorreu um erro inesperado.',
      });
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div style={{ minHeight: '100vh', display: 'flex', alignItems: 'center', justifyContent: 'center', padding: '1rem', background: 'var(--color-bg)' }}>
      <motion.div 
        initial={{ opacity: 0, scale: 0.95, y: 20 }}
        animate={{ opacity: 1, scale: 1, y: 0 }}
        transition={{ duration: 0.5, type: 'spring' }}
        className="glass-panel" 
        style={{ width: '100%', maxWidth: '400px', padding: '2.5rem' }}
      >
        <div style={{ display: 'flex', flexDirection: 'column', alignItems: 'center', marginBottom: '2.5rem' }}>
          <div style={{ width: 48, height: 48, background: 'var(--color-primary)', borderRadius: '12px', display: 'flex', alignItems: 'center', justifyContent: 'center', color: 'white', marginBottom: '1rem' }}>
            <Scale size={28} />
          </div>
          <h1 className="text-serif" style={{ fontSize: '1.5rem', margin: 0 }}>Nova Senha</h1>
          <p className="text-muted" style={{ fontSize: '0.875rem', textAlign: 'center', marginTop: '0.5rem' }}>
            Digite sua nova senha de acesso.
          </p>
        </div>

        <form onSubmit={handleUpdate} style={{ display: 'flex', flexDirection: 'column', gap: '1.25rem' }}>
          <div>
            <label style={{ display: 'block', fontSize: '0.875rem', fontWeight: 500, marginBottom: '0.5rem', color: 'var(--color-text-muted)' }}>Nova Senha</label>
            <div style={{ position: 'relative' }}>
              <Lock size={18} style={{ position: 'absolute', left: '1rem', top: '50%', transform: 'translateY(-50%)', color: 'var(--color-text-muted)' }} />
              <input 
                type="password" 
                placeholder="M├¡nimo 6 caracteres"
                value={password}
                onChange={(e) => setPassword(e.target.value)}
                style={{ width: '100%', padding: '0.75rem 1rem 0.75rem 2.5rem', background: 'rgba(0,0,0,0.03)', border: '1px solid var(--color-border)', borderRadius: '8px', color: 'var(--color-text)' }}
              />
            </div>
          </div>

          <div>
            <label style={{ display: 'block', fontSize: '0.875rem', fontWeight: 500, marginBottom: '0.5rem', color: 'var(--color-text-muted)' }}>Confirmar Nova Senha</label>
            <div style={{ position: 'relative' }}>
              <Lock size={18} style={{ position: 'absolute', left: '1rem', top: '50%', transform: 'translateY(-50%)', color: 'var(--color-text-muted)' }} />
              <input 
                type="password" 
                placeholder="Repita a senha"
                value={confirmPassword}
                onChange={(e) => setConfirmPassword(e.target.value)}
                style={{ width: '100%', padding: '0.75rem 1rem 0.75rem 2.5rem', background: 'rgba(0,0,0,0.03)', border: '1px solid var(--color-border)', borderRadius: '8px', color: 'var(--color-text)' }}
              />
            </div>
          </div>

          <button 
            type="submit" 
            className="btn-primary" 
            disabled={isLoading || !password || !confirmPassword}
            style={{ 
              marginTop: '1rem', 
              width: '100%', 
              padding: '0.875rem',
              cursor: (isLoading || !password || !confirmPassword) ? 'not-allowed' : 'pointer',
              opacity: (isLoading || !password || !confirmPassword) ? 0.7 : 1,
            }}
          >
            {isLoading ? 'Salvando...' : 'Salvar e Entrar'}
          </button>
        </form>
      </motion.div>
    </div>
  );
}
